sql:
SELECT SUM(total_points) AS total_points_earned
FROM activity_records
WHERE participant_id = 0;

SELECT total_points
FROM activity_records
WHERE activity_type = 'running';

SELECT COUNT(record_id) AS total_activity_records
FROM activity_records
WHERE participant_id = 1;

external_knowledge:
- "fire-starters in physical activities" refers to the types of physical activities; 
- "ignited significant fat burn" refers to average calories burned > 100; 
- "hottest to coolest" means in descending order of average calories burned.

sql:
SELECT COUNT(*) AS failed_checks_count
FROM data_integrity_checks
WHERE result = 'fail';

SELECT activity_type, SUM(total_points) AS total_points_earned
FROM activity_records
GROUP BY activity_type;

SELECT interval_name
FROM time_intervals
WHERE interval_length = 60;

SELECT MAX(total_points) AS max_points
FROM activity_records
WHERE date BETWEEN '2023-05-01' AND '2023-05-31';
